insert into booking (
    room_id, subject, booker_id, booker_name, start_time_ms, end_time_ms,
    attendee_count, status, approval_status, remark, version, recurrence_type,
    recurrence_end_date, parent_id, series_index, created_at_ms, updated_at_ms
) values (
    #{roomId}, #{subject}, #{bookerId}, #{bookerName}, #{startTimeMs}, #{endTimeMs},
    #{attendeeCount}, #{status}, #{approvalStatus}, #{remark}, #{version}, #{recurrenceType},
    #{recurrenceEndDate,jdbcType=DATE}, #{parentId}, #{seriesIndex}, #{createdAtMs}, #{updatedAtMs}
)

mapper.select:
select 
from booking
where room_id = #{roomId}
  and status <> 'CANCELED'
  and approval_status <> 'REJECTED'
  and start_time_ms < #{newEndMs}
  and end_time_ms > #{newStartMs}

    and id <> #{excludeBookingId}

order by start_time_ms asc

select 
from booking
where booker_id = #{bookerId}
  and start_time_ms >= #{dayStartMs}
  and start_time_ms < #{dayEndMs}
  and status <> 'CANCELED'
order by start_time_ms asc

select count(1)
from booking
where booker_id = #{bookerId}
  and status <> 'CANCELED'
  and approval_status <> 'REJECTED'
  and start_time_ms >= #{dayStartMs}
  and start_time_ms < #{dayEndMs}

    and id <> #{excludeBookingId}

select 
from booking
where room_id = #{roomId}
  and start_time_ms < #{dayEndMs}
  and end_time_ms >= #{dayStartMs}
order by start_time_ms asc

select 
from booking


        and booker_id = #{bookerId}


        and lower(subject) like concat('%', lower(#{keyword}), '%')


        and room_id = #{roomId}


        and status = #{status}


        and start_time_ms >= #{startTimeFrom}


        and start_time_ms <= #{startTimeTo}


order by start_time_ms desc

select 
from booking

    and approval_status = 'PENDING'
    and status <> 'CANCELED'

        and room_id = #{roomId}


        and room_id in (
            select id from meeting_room where building_id = #{buildingId}
        )


        and booker_id = #{bookerId}


        and lower(subject) like concat('%', lower(#{keyword}), '%')


        and start_time_ms >= #{startTimeFrom}


        and start_time_ms <= #{startTimeTo}


order by start_time_ms asc
